/**
 * Full JetBrains Mono Nerd Font Mono (nerd-fonts v3.4.0, OFL 1.1), embedded as a base64 woff2
 * string constant rather than a loose `.woff2` asset — `build:server` (`tsc -p
 * tsconfig.build.json`, include: src/server, src/shared) does not copy non-`.ts` files, and
 * `package.json`'s `"files": ["dist"]` would silently drop any asset not compiled from source, so
 * only a `.ts` string constant ships in the published npm package.
 * @remarks The bundled cmap aliases Claude Code's U+23FA and U+23F5 symbols to the font's
 * U+25CF circle and U+25B6 triangle glyphs. Keeping those same-cell glyphs in the selected web
 * font avoids platform-dependent system fallback and preserves xterm's monospace canvas metrics.
 * Redistributing this font, even base64-embedded, still requires carrying its license.
 * @see docs/licenses/JetBrainsMono-NerdFont-OFL.txt
 */
export const FONT_FAMILY = "JetBrains Mono Nerd Font Mono";

export const FONT_SPEC = `15px "${FONT_FAMILY}"`;

export const NERD_FONT_WOFF2_BASE64 =
  "";
